mapper.select:
SELECT * FROM ( SELECT T1.COURSE_NO, T1.COURSE_NM, T1.COURSE_INFO, T1.COURSE_PATH_NM, T1.COURSE_DSTNC, T1.COURSE_REQ_TM, ROW_NUMBER() OVER(ORDER BY T1.COURSE_REQ_TM DESC) AS RNUM, COUNT(*) OVER() AS TOTAL_CNT FROM course T1 WHERE 1=1
AND T1.COURSE_NM LIKE '%' || #{searchWord} || '%'
AND T1.COURSE_INFO LIKE '%' || #{searchWord} || '%'
AND T1.COURSE_TYPE = #{searchDiv}
) T1 WHERE RNUM BETWEEN #{pageSize} * (#{pageNo} - 1) + 1 AND #{pageSize} * (#{pageNo} - 1) + #{pageSize}
